sql:
SELECT cf.company_name, cf.total_assets, mi.index_name, mi.value
FROM company_financials cf
JOIN market_indices mi ON STRFTIME('%Y', mi.date) = cf.fiscal_year;

SELECT volume 
FROM stock_prices 
WHERE stock_symbol = 'AAPL' AND date = '2017-01-17';

SELECT AVG(pe_ratio) AS average_pe_ratio
FROM stock_symbols
WHERE market_cap > 1000000000000;

external_knowledge:
- "bustling stocks" refers to stocks with high trading volume;
- "average trading activity" is represented by the average volume of trades for each stock;
- "most recent closing prices" are the latest recorded closing prices for each stock.

sql:
SELECT stock_symbol
FROM stock_prices
WHERE high_price = (SELECT MAX(high_price) FROM stock_prices);

SELECT user_name
FROM users
ORDER BY user_name ASC;

SELECT holding_id, stock_symbol
FROM portfolio_holdings
ORDER BY holding_id;

SELECT user_name, role
FROM users
WHERE role = 'analyst';

SELECT stock_symbol, quantity, current_price
FROM portfolio_holdings
WHERE stock_symbol = 'MSFT';
